1	'use client';
2	
3	import { AspectRatio, Image, type ImageProps, Skeleton } from '@mantine/core';
4	import { useCallback, useEffect, useRef, useState } from 'react';
5	
6	export interface Props extends Omit<ImageProps, 'onLoad' | 'onError'> {
7	    /** Width / height ratio the space is reserved at, e.g. 1 for square, 3 / 2 for a flag. */
8	    ratio: number;
9	    alt: string;
10	    title?: string;
11	    /** Called once the image has finished loading, or failed to. */
12	    onReady?: () => void;
13	}
14	
15	/**
16	 * Wraps Mantine's Image in a fixed-ratio box so its footprint is reserved
17	 * before the src has loaded, and shows a Skeleton over it until then —
18	 * avoiding the layout shift a bare `Image` causes while its bytes are still
19	 * in flight. `w` sizes the reserved box itself (defaulting to the full width
20	 * of its container); the image inside always fills that box.
21	 */
22	export const ImageWithPlaceholder = ({ ratio, radius, w = '100%', alt, onReady, ...imageProps }: Props) => {
23	    const [loaded, setLoaded] = useState(false);
24	
25	    const onReadyRef = useRef(onReady);
26	    useEffect(() => {
27	        onReadyRef.current = onReady;
